// Validate webhook payload
const body = $input.first().json.body || $input.first().json;
const requiredFields = ['email_id', 'subject', 'owner_agent'];
const missing = requiredFields.filter(f => !body[f]);

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

return [{
  json: {
    email_id: body.email_id,
    subject: body.subject,
    thread_length: body.thread_length || 0,
    sender: body.sender || 'unknown',
    owner_agent: body.owner_agent
  }
}];

// Build the Ollama prompt from the email thread
// IMPORTANT: email content goes to Ollama (local) ONLY — never to any external API
const thread = $input.first().json;
const emailId = $('Validate Payload').first().json.email_id;
const subject = $('Validate Payload').first().json.subject;

const threadText = Array.isArray(thread.messages)
  ? thread.messages.map((m, i) => `Message ${i+1} (from: ${m.from || 'unknown'}, date: ${m.date || 'unknown'}):\n${m.body || m.text || ''}`).join('\n\n---\n\n')
  : JSON.stringify(thread);

const prompt = `Summarize this email thread. Key points? What action is needed? Keep response under 150 words.\n\nSubject: ${subject}\n\n${threadText}`;

return [{
  json: {
    prompt: prompt,
    email_id: emailId,
    subject: subject,
    owner_agent: $('Validate Payload').first().json.owner_agent
  }
}];

// Build the response to return to Pulse
const ollamaResult = $input.first().json;
const emailId = $('Build Ollama Prompt').first().json.email_id;
const subject = $('Build Ollama Prompt').first().json.subject;
const ownerAgent = $('Build Ollama Prompt').first().json.owner_agent;

const summary = ollamaResult.response || 'Unable to generate summary.';

// Try to extract suggested action from the summary
let suggestedAction = 'review';
const lowerSummary = summary.toLowerCase();
if (lowerSummary.includes('reply') || lowerSummary.includes('respond')) suggestedAction = 'reply';
else if (lowerSummary.includes('forward') || lowerSummary.includes('escalate')) suggestedAction = 'forward';
else if (lowerSummary.includes('schedule') || lowerSummary.includes('meeting')) suggestedAction = 'schedule';
else if (lowerSummary.includes('no action') || lowerSummary.includes('fyi')) suggestedAction = 'none';

return [{
  json: {
    email_id: emailId,
    subject: subject,
    owner_agent: ownerAgent,
    summary: summary,
    suggested_action: suggestedAction,
    processed_at: new Date().toISOString()
  }
}];
